const body = $json.body || $json;
const context = body.planning_context || {};
const date = body.agenda_date || context.date;
const minBreak = Number(context?.planning_window?.min_break_minutes ?? 15);

const priorityWeight = { urgent: 0, high: 1, medium: 2, low: 3 };
const slots = (context.free_slots || []).map(slot => ({
  start: new Date(slot.start),
  end: new Date(slot.end),
  label: slot.label,
  duration_minutes: Number(slot.duration_minutes || 0),
}));

const tasks = (context.tasks || [])
  .filter(task => !task.is_completed)
  .sort((a, b) => {
    const pa = priorityWeight[a.priority || 'medium'] ?? 2;
    const pb = priorityWeight[b.priority || 'medium'] ?? 2;
    if (pa !== pb) return pa - pb;
    const da = a.due_at ? new Date(a.due_at).getTime() : Number.MAX_SAFE_INTEGER;
    const db = b.due_at ? new Date(b.due_at).getTime() : Number.MAX_SAFE_INTEGER;
    if (da !== db) return da - db;
    return String(a.title).localeCompare(String(b.title));
  });

function addMinutes(dateValue, minutes) {
  return new Date(dateValue.getTime() + minutes * 60 * 1000);
}

const plannedTasks = [];
const unscheduledTasks = [];

for (const task of tasks) {
  const duration = Math.max(15, Math.min(Number(task.estimated_duration_minutes || 60), 480));
  let placed = false;

  for (let i = 0; i < slots.length; i++) {
    const slot = slots[i];
    const availableMinutes = Math.floor((slot.end.getTime() - slot.start.getTime()) / 60000);
    if (availableMinutes < duration) continue;

    const scheduledStart = new Date(slot.start);
    const scheduledEnd = addMinutes(scheduledStart, duration);

    plannedTasks.push({
      task_id: task.id,
      title: task.title,
      priority: task.priority || 'medium',
      estimated_duration_minutes: duration,
      due_at: task.due_at || null,
      scheduled_start: scheduledStart.toISOString(),
      scheduled_end: scheduledEnd.toISOString(),
      source: 'n8n_rule_based_planner',
    });

    const nextStart = addMinutes(scheduledEnd, minBreak);
    if (nextStart >= slot.end) {
      slots.splice(i, 1);
    } else {
      slots[i] = { ...slot, start: nextStart };
    }

    placed = true;
    break;
  }

  if (!placed) {
    unscheduledTasks.push({
      task_id: task.id,
      title: task.title,
      priority: task.priority || 'medium',
      estimated_duration_minutes: duration,
      due_at: task.due_at || null,
      reason: 'No free slot long enough inside the planning window.',
    });
  }
}

const plan = {
  date,
  planning_window: context.planning_window || {},
  stats: {
    event_count: (context.events || []).length,
    task_count: tasks.length,
    planned_task_count: plannedTasks.length,
    unscheduled_task_count: unscheduledTasks.length,
    original_free_slot_count: (context.free_slots || []).length,
  },
  schedule: plannedTasks,
  unscheduled_tasks: unscheduledTasks,
  assistant_message: plannedTasks.length
    ? `I scheduled ${plannedTasks.length} task(s) using the n8n rule-based planner.`
    : 'I could not schedule any tasks into the available free slots.',
};

return [{
  json: {
    status: 'generated',
    source: 'n8n_rule_based',
    user_id: body.user_id,
    user_email: body.user_email,
    agenda_date: date,
    plan,
  }
}];
